mapper.select:
select items.*,
       user.name as userName,
       category.name as categoryName,
       (select count(*) from `collect` where collect.item_id = items.id) as collectCount
from `items`
left join user on items.user_id = user.id
left join category on items.category_id = category.id

     and items.name like concat('%', #{name}, '%')
     and items.user_id = #{userId}
     and items.status = #{status}
     and items.category_id = #{categoryId}
     and items.check_status = #{checkStatus}

order by items.id desc

mapper.update:
update `items`
name = #{name}, img = #{img}, description = #{description}, requirement = #{requirement}, status = #{status}, user_id = #{userId}, time = #{time}, check_status = #{checkStatus}, reason = #{reason}, category_id = #{categoryId},
where id = #{id}
